#include <bits/stdc++.h>
using namespace std;
long long n,d,v[100005],a[100005],feul=1,ans,p=0;
int main(){
    cin>>n>>d;
    bool flag=false;
    for(int i=2;i<=n;i++){
        cin>>v[i];
        v[i]+=v[i-1];
    }
    for(int i=1;i<=n;i++)cin>>a[i];
    for(int i=2;i<=n;i++){
        if(a[i]<a[feul]){
            ans+=ceil((1.0*v[i]-1.0*p)/(1.0*d))*a[feul],p=ceil((v[i]*1.0)/double(d))*d,feul=i;
            if(i==n)flag=true;
        }
    }
    if(!flag){
    	ans+=ceil(1.0*(v[n]-p)/(1.0*d))*a[feul];
	}
    cout<<ans;
    return 0;
}
